import{_ as a,o,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Mapbox Geocoding API","description":"Forward and reverse geocoding with Mapbox Search API.","frontmatter":{"title":"Mapbox Geocoding API","description":"Forward and reverse geocoding with Mapbox Search API."},"headers":[],"relativePath":"gis/geocoding/mapbox-geocoding-api/README.md","filePath":"gis/geocoding/mapbox-geocoding-api/README.md"}'),r={name:"gis/geocoding/mapbox-geocoding-api/README.md"};function s(n,e,d,l,c,p){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="mapbox-geocoding-api" tabindex="-1">Mapbox Geocoding API <a class="header-anchor" href="#mapbox-geocoding-api" aria-label="Permalink to &quot;Mapbox Geocoding API&quot;">тАЛ</a></h1><p>Mapbox <strong>Geocoding API</strong> (part of Mapbox Search) converts addresses to coordinates and vice versa, with global coverage and structured feature types.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">тАЛ</a></h2><ul><li><a href="https://docs.mapbox.com/api/search/geocoding/" target="_blank" rel="noreferrer">Mapbox Geocoding API</a></li><li><a href="https://docs.mapbox.com/help/getting-started/geocoding/" target="_blank" rel="noreferrer">Getting started with geocoding</a></li><li><a href="https://docs.mapbox.com/help/getting-started/geocoding/#result-prioritization-in-reverse-geocoding" target="_blank" rel="noreferrer">Reverse geocoding result prioritization</a></li></ul><h2 id="endpoints-v6" tabindex="-1">Endpoints (v6) <a class="header-anchor" href="#endpoints-v6" aria-label="Permalink to &quot;Endpoints (v6)&quot;">тАЛ</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Use</th></tr></thead><tbody><tr><td><strong>Forward</strong></td><td><code>mapbox.places</code> тАФ query string тЖТ ranked features</td></tr><tr><td><strong>Reverse</strong></td><td>lat,lon тЖТ nearest address/place/POI</td></tr></tbody></table><p>Returns GeoJSON-like features with <code>place_type</code>, relevance, and bounding boxes.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">тАЛ</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.mapbox.com/search/geocode/v6/forward?q=1600+pennsylvania&amp;access_token=YOUR_TOKEN&quot;</span></span></code></pre></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">тАЛ</a></h2><ul><li>Set <code>proximity</code> to bias results near a map center</li><li>Use <code>types</code> filter (<code>address</code>, <code>place</code>, <code>poi</code>, тАж) to reduce noise</li><li>Cache responses тАФ geocoding is billed per request</li></ul><h2 id="in-this-section" tabindex="-1">In this section <a class="header-anchor" href="#in-this-section" aria-label="Permalink to &quot;In this section&quot;">тАЛ</a></h2><ul><li><a href="./useful-mapbox-geocoding-api-info.html">Useful Mapbox Geocoding API Info</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">тАЛ</a></h2><ul><li><a href="./../README.html">Geocoding</a></li></ul>',15)])])}const b=a(r,[["render",s]]);export{g as __pageData,b as default};
